-- Ghana Tertiary UniConnect Dataset - part 16
-- Run parts sequentially in Supabase SQL Editor.

insert into public.departments (source_id, university_id, faculty_id, name) select 'acm_computing_and_information_technology_cybersecurity', u.id, f.id, 'Cybersecurity' from public.universities u join public.faculties f on f.source_id = 'acm_computing_and_information_technology' where u.source_id = 'acm' and not exists (select 1 from public.departments where source_id = 'acm_computing_and_information_technology_cybersecurity' or (university_id = u.id and name = 'Cybersecurity'));
update public.departments set source_id = coalesce(source_id, 'acm_computing_and_information_technology_cybersecurity'), faculty_id = (select id from public.faculties where source_id = 'acm_computing_and_information_technology') where source_id = 'acm_computing_and_information_technology_cybersecurity' or (name = 'Cybersecurity' and university_id = (select id from public.universities where source_id = 'acm'));
